+        let w2 = c2.load(Ordering::SeqCst);
+        h2.verify_all_oracles();
+
+        assert_with_log!(
+            w1 == w2,
+            "same seed must produce identical work count",
+            w1,
+            w2
+        );
+    }
+
+    test_complete!("e2e_lifecycle_multi_seed_determinism");
+}

